args.ReplacementContent:
"                  <div className="flex items-center gap-4">
                    {/* Step Progress - More subtle */}
                    <div className="flex items-center gap-1.5">
                      {[1, 2, 3].map((step) => (
                        <div key={step} className="flex items-center">
                          <div className={`w-7 h-7 rounded-full flex items-center justify-center text-[10px] font-black transition-all ${
                            registerStep === step 
                              ? 'bg-primary-600 text-white shadow-md' 
                              : registerStep > step 
                                ? 'bg-emerald-500 text-white' 
                                : 'bg-slate-200 text-slate-400'
                          }`}>
                            {registerStep > step ? <Check size={12} /> : step}
                          </div>
                          {step < 3 && (
                            <div className={`w-6 h-0.5 mx-0.5 rounded-full ${registerStep > step ? 'bg-emerald-500' : 'bg-slate-200'}`} />
                          )}
                        </div>
                      ))}
                    </div>

                    <button 
                      onClick={() => {
                        setIsRegisteringVacancy(false);
                        setRegisterStep(1);
                      }}
                      className="w-10 h-10 bg-slate-50 rounded-xl flex items-center justify-center text-slate-400 hover:bg-slate-100 transition-colors"
                    >
                      <CloseIcon size={20} />
                    </button>
                  </div>"

